use std::borrow::Cow;

struct Message<'a> {
    text: Cow<'a, str>, // borrowed OR owned
}

impl<'a> Message<'a> {
    fn from_static(s: &'a str) -> Self {
        Message { text: Cow::Borrowed(s) }
    }
    fn from_owned(s: String) -> Message<'static> {
        Message { text: Cow::Owned(s) }
    }
    fn as_str(&self) -> &str {
        &self.text
    }
}

fn greet(name: Option<&str>) -> String {
    let msg = match name {
        Some(n) => Message::from_owned(format!("Hello, {}!", n)),
        None => Message::from_static("Hello, stranger!"),
    };
    msg.as_str().to_owned()
}

fn main() {
