// Self-referential struct (String owning data + slice of that data)
// requires unsafe or a crate like ouroboros/self_cell in safe Rust.
// The idiomatic safe approach: store indices instead of references.

struct ParseCache {
    input: String,
    word_ranges: Vec<std::ops::Range<usize>>,
}

impl ParseCache {
    fn new(s: String) -> Self {
        let word_ranges = s.split_whitespace()
            .map(|w| {
                let start = w.as_ptr() as usize - s.as_ptr() as usize;
                start..start + w.len()
            })
            .collect();
        ParseCache { input: s, word_ranges }
    }
    fn words(&self) -> impl Iterator<Item = &str> {
        self.word_ranges.iter().map(|r| &self.input[r.clone()])
    }
}

fn main() {
    let cache = ParseCache::new(String::from("hello world foo"));
    for w in cache.words() {
        println!("{}", w);
    }
}

